sap.ui.define([
  "sap/ui/core/UIComponent",
  "sap/ui/model/json/JSONModel",
  "sap/ui/model/odata/v2/ODataModel"
], function(UIComponent, JSONModel, ODataModel) {
  "use strict";

  return UIComponent.extend("z.fiori.sales.Component", {
    metadata: {
      manifest: "json"
    },

    init: function() {
      UIComponent.prototype.init.apply(this, arguments);

      // OData model to backend RAP service
      var oDataModel = new ODataModel({
        serviceUrl: "/sap/opu/odata4/sap/z_sales_order_srv/",
        synchronizationMode: "Deferred",
        useBatch: true
      });

      this.setModel(oDataModel, "sales");

      // Device model for responsive layout
      var oDeviceModel = new JSONModel(Device);
      oDeviceModel.setDefaultBindingMode("OneWay");
      this.setModel(oDeviceModel, "device");

      // Router for view navigation
      this.getRouter().initialize();
    }
  });
});

{
  "_version": "1.58.0",
  "sap.app": {
    "id": "z.fiori.sales",
