// OData batch operation (client-side)
var oModel = this.getView().getModel();
oModel.setUseBatch(true);  // Enable batch processing

// Submit all pending changes in one batch request
// This bundles Create, Update, Delete into a single HTTP call
oModel.submitChanges({
  success: function(oData) {
    // All changes committed atomically
    sap.m.MessageToast.show("All changes saved");
  },
  error: function(oError) {
    sap.m.MessageBox.error("Batch failed: " + oError.message);
  }
});

// CDS projection to limit returned fields (server-side)
@EndUserText.label: 'Sales Order List (minimal fields)'
define view Z_SalesOrder_List
  as select from I_SalesOrder
{
  key SalesOrderID,
      CustomerName,
      TotalNetAmount,
      CurrencyCode,
      CreationDate
  " Only 5 fields instead of 50.
  " Reduces OData response size by ~80%.
}

