// Cross-application navigation in controller
sap.ui.define([
  "sap/ushell/Container"
], function(Container) {
  "use strict";

  return Controller.extend("z.fiori.sales.controller.List", {
    onItemPress: function(oEvent) {
      var oContext = oEvent.getSource().getBindingContext();
      var sOrderId = oContext.getProperty("SalesOrderID");

      // Navigate via intent — NOT via direct URL
      Container.getServiceAsync("CrossApplicationNavigation").then(
        function(oNavService) {
          oNavService.toExternal({
            target: {
              semanticObject: "SalesOrder",
              action: "Display"
            },
            params: {
              SOID: sOrderId
            }
          });
        }
      );
    }
  });
});

// Offline Fiori App Configuration
// sap.ui5 > models in manifest.json

"models": {
  "": {
    "dataSource": "mainService",
    "settings": {
      "useBatch": true,
      "defaultBindingMode": "TwoWay",
      "offline": {
        "enabled": true,
        "storeName": "SalesOrderStore",
        "syncInterval": 300,  // seconds
        "conflictResolution": "lastWriteWins",
        "maxOfflineDataSize": 50  // MB
      }
    }
  }
}

// Manual sync trigger
sap.ui.define([
  "sap/ui/model/odata/v2/ODataModel"
], function(ODataModel) {
  "use strict";

  return Controller.extend("z.fiori.offline.controller.Main", {
    onSync: function() {
      var oModel = this.getView().getModel();

      if (navigator.onLine) {
        oModel.submitChanges({
          success: function() {
            sap.m.MessageToast.show("Sync completed");
          },
          error: function(oError) {
            sap.m.MessageBox.error("Sync failed: " + oError.message);
          }
        });
      } else {
        // Queue changes locally — will be sent when online
        sap.m.MessageToast.show("Changes saved locally. Will sync when online.");
      }
    },

    onCheckConnectivity: function() {
      if (navigator.onLine) {
        sap.m.MessageToast.show("Online mode");
      } else {
        sap.m.MessageToast.show("Offline mode — local data only");
      }
    }
  });
});

// UI5 Module Definition — shared library
// For reuse across multiple Fiori apps (mono-repo pattern)

sap.ui.define([
  "sap/ui/base/Object",
  "sap/ui/model/Sorter",
  "sap/ui/model/Filter"
], function(BaseObject, Sorter, Filter) {
  "use strict";

  /**
   * Shared utilities across all Sales Fiori apps
   */
  return BaseObject.extend("z.fiori.shared.SalesUtils", {
    constructor: function() {
      BaseObject.apply(this, arguments);
    },

    formatCurrency: function(value, currency) {
      return Number(value).toLocaleString("en-US", {
        style: "currency",
        currency: currency || "USD"
      });
    },

    buildSalesFilters: function(oSearchTerm) {
      var aFilters = [];
      if (oSearchTerm) {
        aFilters.push(new Filter({
          filters: [
            new Filter("SalesOrderID", "Contains", oSearchTerm),
            new Filter("CustomerName", "Contains", oSearchTerm)
          ],
          and: false  // OR logic
        }));
      }
      return aFilters;
    },

    getSalesSorter: function() {
      return new Sorter({
        path: "CreationDate",
        descending: true
      });
    }
  });
});

